#' Create a risk parity portfolio
#'
#' @param universe_m_d_ref A dataframe with tickers, is_eligible and final_signal columns generated by filter_stock_universe
#' @param returns_xts_upd_ref A dataframe in which columns represent tickers present in universe_m_d_ref and row represent periods
#' It should include all stocks in current_stock_universe and a dates column with at least cov_matrix_sample_size periods before current_date
#' @param cov_matrix_sample_size Number of periods to subset returns_d_ref sample when estimating the covariance_matrix. A high number will provide
#' higher degrees of freedom, but old returns might not reflect current risk due to parameter shift. A low number will tend to expose estimation
#' to dimensionality curse.
#' @param cov_estimation_method One of SAM (Sample), EWMA, CC (Constant Correlation), PCA1, PCA2, Shrink_ID or Shrink_CC.
#' If NULL, blending_method can only be EW or IR
#' @param groups_m_d_ref A dataframe with id, tickers, dates and group classification columns to be used to fill NAs in the return sample
#' @return
#' @export
#'
#' @examples
create_risk_parity_portfolio <- function(universe_m_d_ref, returns_xts_upd_ref, cov_matrix_sample_size, cov_estimation_method, groups_m_d_ref,
                                         active_returns, selected_benchmark_xts_upd_ref,
                                         verbose = TRUE){

  #Message
  if(verbose){
    tictoc::tic()
    cat("\n")
    cat("Deriving weights through RP...")
  }

  #Assign eligible_universe_m_d_ref
  eligible_universe_m_d_ref <- universe_m_d_ref

  #Calculate covariance matrix of eligible stocks
  try(eligible_universe_m_d_ref <- universe_m_d_ref %>% dplyr::filter(is_eligible == 1))

  #Generate covariance matrix
  covariance_matrix <- estimate_covariance_matrix(tickers = eligible_universe_m_d_ref$tickers, returns_xts_upd_ref = returns_xts_upd_ref,
                                                  cov_matrix_sample_size = cov_matrix_sample_size,
                                                  cov_estimation_method = cov_estimation_method, groups_m_d_ref = groups_m_d_ref,
                                                  active_returns = active_returns, selected_benchmark_xts_upd_ref = selected_benchmark_xts_upd_ref)

  #Create rp_weights object
  rp <- riskParityPortfolio::riskParityPortfolio(Sigma = covariance_matrix)
  rp_weights <- data.frame(tickers = names(rp$w), risk_contribution = rp$relative_risk_contribution, weights = rp$w) #get weights and relative risk contribution

  #Merge with current_stock_universe
  universe_m_d_ref <- dplyr::left_join(universe_m_d_ref, rp_weights, by = "tickers")

  #Replace NAs with zeros
  universe_m_d_ref[which(is.na(universe_m_d_ref$weights)),"weights"] <- 0

  #Message
  if(verbose){
    cat("\n")
    cat(crayon::green(paste("Risk Parity weights succesfully defined")))
    cat("\n")
    elapsed_time <- tictoc::toc()
  }


  #Return
  return(universe_m_d_ref)
}
